question:
Analyze the following code snippet and predict its output. Justify your answer by explaining the object slicing behavior that occurs and how it relates to exception handling. Then, propose a better practice to avoid this issue.

```cpp
#include <iostream>
#include <exception>
using namespace std;

class BaseException : public exception {
public:
    virtual const char* what() const noexcept override {
        return "Base Exception";
    }
};

class DerivedException : public BaseException {
public:
    virtual const char* what() const noexcept override {
        return "Derived Exception";
    }
};

int main() {
    try {
        throw DerivedException();
    }
    catch (BaseException e) { // Catching by value
        cout << e.what() << endl;
    }
    return 0;
}
```
